    categories: ["Epilepsy", "COVID-19", "Education"],
    keywords: ["Spanish-speaking population", "health care disparities", "pediatric epilepsy", "quality improvement", "telemedicine", "Adolescent", "Child", "Child, Preschool", "Female", "Humans"],
    isMemberPaper: true,
